import React, { useState } from "react";
import axios from "axios";

function AddProduct() {
  const [name, setName] = useState("");
  const [quantity, setQuantity] = useState("");
  const [price, setPrice] = useState("");
  const [msg, setMsg] = useState(null);

  const submit = () => {
    if (!name || !quantity || !price) {
      setMsg({ type: "error", text: "Please fill in all fields." });
      return;
    }
    axios.post("http://localhost:5000/addproduct", { name, quantity, price })
      .then(() => {
        setMsg({ type: "success", text: `✓ "${name}" added successfully!` });
        setName(""); setQuantity(""); setPrice("");
      })
      .catch(() => setMsg({ type: "error", text: "Failed to add product. Is the backend running?" }));
  };

  return (
    <div className="page-enter">
      <div className="page-header">
        <h2>Add Product</h2>
        <p>Add a new item to your inventory</p>
      </div>

      <div className="card" style={{ maxWidth: 500 }}>
        {msg && <div className={`alert alert-${msg.type}`}>{msg.text}</div>}

        <div className="form-group">
          <label>Product Name</label>
          <input placeholder="e.g. Laptop" value={name} onChange={e => setName(e.target.value)} />
        </div>

        <div className="form-group">
          <label>Quantity</label>
          <input type="number" placeholder="e.g. 10" value={quantity} onChange={e => setQuantity(e.target.value)} />
        </div>

        <div className="form-group">
          <label>Price (₹)</label>
          <input type="number" placeholder="e.g. 50000" value={price} onChange={e => setPrice(e.target.value)} />
        </div>

        <button className="btn btn-success" onClick={submit}>Add Product</button>
      </div>
    </div>
  );
}

export default AddProduct;
